mapper.select:
select
from appointment a left join sys_user su on a.user_id = su.id left join counselor c on a.counselor_id = c.id left join sys_user cu on c.user_id = cu.id left join counselor_schedule cs on a.schedule_id = cs.id left join consultation_record cr on a.id = cr.appointment_id left join upload_file uf on cr.attachment_file_id = uf.id
and a.status in (2, 3)
and a.appointment_no like concat('%', #{appointmentNo}, '%')
and a.user_id = #{userId}
and a.counselor_id = #{counselorId}
and a.status = #{status}
and cr.id is not null
and cr.id is null
order by a.update_time desc, a.id desc

select count(*)
from consultation_record
where appointment_id = #{appointmentId}
